+/// Verify GlobalInjector cancel/ready injection + pop stays within allocation
+/// ceilings.
+#[test]
+fn global_injector_allocation_ceiling() {
+    let _guard = ALLOC_TEST_GUARD
+        .lock()
+        .unwrap_or_else(std::sync::PoisonError::into_inner);
