+        injector.inject_cancel(task(i), 5);
+        injector.inject_ready(task(i + 100), 3);
+        injector.inject_timed(task(i + 200), Time::from_nanos(u64::from(i) + 1));
+    }
+    for _ in 0..100 {
+        injector.pop_cancel();
+        injector.pop_ready();
+        injector.pop_timed_if_due(Time::from_nanos(200));
